@* Displays a single task card with title, assignee, priority badge, due date, and move buttons *@

<div class="task-card">
    <div class="task-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge @GetPriorityClass()">@Task.Priority</span>
    </div>
    <div class="task-assignee">@Task.Assignee</div>
    <div class="task-due">@Task.DueDate.ToString("MMM dd")</div>
    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="() => OnMoveLeft.InvokeAsync(Task.Id)">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="() => OnMoveRight.InvokeAsync(Task.Id)">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    private string GetPriorityClass() => Task.Priority switch
    {
        "High" => "priority-high",
        "Medium" => "priority-medium",
        "Low" => "priority-low",
        _ => ""
    };
}

@* Inline form for creating a new task within a column *@

<div class="add-task-form">
    <div class="form-field">
        <label>Title</label>
        <input type="text" @bind="title" placeholder="Task title" />
    </div>
    <div class="form-field">
        <label>Assignee</label>
        <input type="text" @bind="assignee" placeholder="Assignee name" />
    </div>
    <div class="form-field">
        <label>Priority</label>
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
    </div>
    <div class="form-field">
        <label>Due Date</label>
        <input type="date" @bind="dueDate" />
    </div>
    <div class="form-actions">
        <button class="btn-save" @onclick="HandleSave" disabled="@saving">
            @(saving ? "Saving..." : "Save")
        </button>
        <button class="btn-cancel" @onclick="HandleCancel" disabled="@saving">Cancel</button>
    </div>
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="form-error">@errorMessage</div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public string DefaultStatus { get; set; } = default!;

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;
    private string? errorMessage;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title) || string.IsNullOrWhiteSpace(assignee))
        {
            errorMessage = "Title and assignee are required.";
            return;
        }

        saving = true;
        errorMessage = null;

        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            saving = false;
        }
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }
}

@* A single Kanban column showing its tasks and an inline add-task form *@

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    <div class="column-footer">
        @if (showForm)
        {
            <AddTaskForm DefaultStatus="@Status"
                         TaskService="TaskService"
                         OnTaskCreated="HandleTaskCreated"
                         OnCancel="() => showForm = false" />
        }
        else
        {
            <button class="btn-add" @onclick="() => showForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = default!;

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

