toolArgs.file_text:
@* A single Kanban column showing its tasks and an inline add-task form *@

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>

    <div class="column-footer">
        @if (showForm)
        {
            <AddTaskForm DefaultStatus="@Status"
                         TaskService="TaskService"
                         OnTaskCreated="HandleTaskCreated"
                         OnCancel="() => showForm = false" />
        }
        else
        {
            <button class="btn-add" @onclick="() => showForm = true">+ Add Task</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = default!;

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<int> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        showForm = false;
        await OnTaskCreated.InvokeAsync(task);
    }
}

